import requests

logger = logging.getLogger()
logger.setLevel(logging.INFO)


class IntegrationRegistry:
    _registry: Dict[str, Callable[[Dict[str, Any]], None]] = {}

    @classmethod
    def register(cls, name: str) -> Callable[[Callable[[Dict[str, Any]], None]], Callable[[Dict[str, Any]], None]]:
        def decorator(fn: Callable[[Dict[str, Any]], None]) -> Callable[[Dict[str, Any]], None]:
            cls._registry[name] = fn
            logger.info("Registered integration '%s' -> %s.%s", name, fn.__module__, fn.__name__)
            return fn
        return decorator

    @classmethod
    def handle(cls, name: str, payload: Dict[str, Any]) -> Any:
        if name not in cls._registry:
            logger.warning("Integration '%s' not registered. Falling back to 'generic'.", name)
            name = "generic"
        return cls._registry[name](payload)


def fetch_and_display(url: str, *, timeout: int = 10, headers: Dict[str, str] | None = None) -> str:
    logger.info("Fetching URL: %s", url)
    response = requests.get(url, timeout=timeout, headers=headers)
    response.raise_for_status()
    logger.info("Fetched %d bytes from %s", len(response.content), url)
    text = response.text
    print(text)
    return text


def _load_external_integrations() -> None:
    """Dynamically load integration modules listed in the INTEGRATION_MODULES env var."""
    modules = os.getenv("INTEGRATION_MODULES")
    if not modules:
        return
    for mod_name in modules.split(","):
        mod_name = mod_name.strip()
        if mod_name:
            try:
                importlib.import_module(mod_name)
                logger.info("Loaded external integration module '%s'", mod_name)
            except Exception as exc:
                logger.exception("Failed to load integration module '%s': %s", mod_name, exc)


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    AWS Lambda entrypoint.
    Expected event format:
    {
        "url": "https://example.com",
        "integration": "partner_name",
        "payload": { ... webhook payload ... }
    }
    """
    url = event.get("url")
    if not url:
        raise ValueError("Event missing required key: 'url'")

    integration_name = event.get("integration", "generic")
    payload = event.get("payload", {})
    IntegrationRegistry.handle(integration_name, payload)

    body = fetch_and_display(url)
    return {
        "statusCode": 200,
        "headers": {"Content-Type": "text/plain"},
        "body": body,
    }


